import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

function ClientDashboard() {
  const [project, setProject] = useState(null);
  const navigate = useNavigate();

  // 1. Check if client is already logged in (Data from localStorage)
  useEffect(() => {
    const loggedInUser = localStorage.getItem('clientUser');
    if (loggedInUser) {
      setProject(JSON.parse(loggedInUser));
    } else {
      // If not logged in, redirect to separate Login Page
      alert("Please login first to view your project status.");
      navigate('/login'); 
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    navigate('/login');
  };

  if (!project) return null; // Loading state

  return (
    <div className="container py-5 mt-5">
      <div className="row justify-content-center">
        <div className="col-lg-8">
          <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
            
            {/* Professional Header */}
            <div className="bg-dark p-4 text-white d-flex justify-content-between align-items-center">
              <div>
                <h4 className="mb-0 fw-bold">Welcome, {project.fullName}!</h4>
                <small className="opacity-75">Tracking: {project.serviceType}</small>
              </div>
              <button className="btn btn-sm btn-outline-danger px-3 fw-bold" onClick={handleLogout}>
                Logout Account
              </button>
            </div>
            
            <div className="card-body p-4 p-lg-5">
              {/* Progress Bar Section */}
              <div className="mb-5">
                <div className="d-flex justify-content-between mb-2">
                  <h6 className="fw-bold">Work Progress</h6>
                  <span className="fw-bold text-primary fs-5">{project.progress}%</span>
                </div>
                <div className="progress rounded-pill shadow-sm" style={{ height: '30px' }}>
                  <div 
                    className="progress-bar progress-bar-striped progress-bar-animated bg-success" 
                    role="progressbar"
                    style={{ width: `${project.progress}%` }}
                  ></div>
                </div>
                <p className="mt-3 text-muted">
                  Current Status: <span className="badge bg-info text-dark ms-2">{project.status || 'Active'}</span>
                </p>
              </div>

              <hr className="my-4" />

              {/* Payment & Financial Info */}
              <div className="row g-4 text-center">
                <div className="col-md-4">
                  <div className="p-3 border rounded-3 bg-light">
                    <small className="text-muted d-block">Total Budget</small>
                    <h5 className="fw-bold">₹{project.totalBudget}</h5>
                  </div>
                </div>
                <div className="col-md-4">
                  <div className="p-3 border rounded-3 bg-light">
                    <small className="text-muted d-block">Advance Paid</small>
                    <h5 className="fw-bold text-success">₹{project.advancePaid}</h5>
                  </div>
                </div>
                <div className="col-md-4">
                  <div className="p-3 border rounded-4 bg-primary text-white shadow-sm">
                    <small className="opacity-75 d-block">Remaining Balance</small>
                    <h5 className="fw-bold mb-0">₹{project.totalBudget - project.advancePaid}</h5>
                  </div>
                </div>
              </div>

              <div className="mt-5 p-3 bg-light rounded-3 small text-center text-muted border">
                <i className="fas fa-info-circle me-2"></i>
                For any changes or revisions, please contact the freelancer directly.
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
}

export default ClientDashboard;
